const config = $('Configuration').first().json;

const github = config.github;

return $input.all().map(item => {

  const {
    updatedAt,
    versionId,
    meta,
    pinData,
    ...workflow
  } = item.json;

  // Stable folder name (contains workflow ID)
  const workflowFolder =
    workflow.name
      .replace(/[<>:"/\\|?*]/g, '')
      .replace(/\s+/g, '-')
      .replace(/-+/g, '-') +
    '__' +
    workflow.id;

  // Human-readable JSON filename
  const workflowFile =
    workflow.name
      .replace(/[<>:"/\\|?*]/g, '')
      .trim() +
    '.json';

return {
  json: {
    workflow,
    workflowId: workflow.id,
    workflowName: workflow.name,

    workflowFolder,
    workflowFile,

    owner: github.owner,
    repo: github.repository,
    branch: github.branch,
    folder: github.workflowFolder,

    documentation: config.documentation
  }
};
});

const results = [];

for (const item of $input.all()) {
  // Decode Base64 safely using native Node.js Buffers
  const decodedText = Buffer.from(item.json.content, 'base64').toString('utf-8');

  // Parse the decoded text string into a JSON object
  const githubWorkflow = JSON.parse(decodedText);

  // Remove fields that should not trigger a Git commit
  delete githubWorkflow.updatedAt;
  delete githubWorkflow.versionId;
  delete githubWorkflow.meta;
  delete githubWorkflow.pinData;

  // Push the cleaned workflow along with its unique GitHub SHA
  results.push({
    json: {
      githubWorkflow,
      sha: item.json.sha,
    }
  });
}

return results;

const results = [];

const currentItems = $('Prepare Workflow').all();
const githubItems = $input.all();

for (let i = 0; i < githubItems.length; i++) {

  const workflow = currentItems[i].json.workflow;
  const githubWorkflow = githubItems[i].json.githubWorkflow;

  const changed =
    JSON.stringify(workflow) !== JSON.stringify(githubWorkflow);

  results.push({
  json: {
    ...currentItems[i].json,
    githubWorkflow: githubItems[i].json.githubWorkflow,
    sha: githubItems[i].json.sha,
    changed
  }
});
}

return results;

